+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://process-triage.dev/schemas/agent-apply/1.0.0",
+  "title": "Agent Apply Output",
+  "description": "Schema for pt agent apply JSON output",
+  "type": "object",
+  "required": ["schema_version", "session_id", "results"],
+  "additionalProperties": true,
+  "properties": {
+    "schema_version": {
+      "type": "string",
+      "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$"
+    },
+    "session_id": {
+      "type": "string",
+      "pattern": "^pt-[0-9]{8}-[0-9]{6}-[a-z0-9]{4}$"
+    },
+    "generated_at": {
+      "type": "string",
+      "format": "date-time"
+    },
+    "host_id": {
+      "type": "string"
+    },
+    "results": {
+      "type": "array",
+      "items": { "$ref": "#/$defs/action_result" }
+    },
+    "summary": {
+      "type": "object",
+      "properties": {
+        "total": { "type": "integer", "minimum": 0 },
+        "successful": { "type": "integer", "minimum": 0 },
+        "skipped": { "type": "integer", "minimum": 0 },
+        "failed": { "type": "integer", "minimum": 0 },
+        "blocked": { "type": "integer", "minimum": 0 },
+        "memory_freed_mb": { "type": "number", "minimum": 0 }
+      }
+    },
+    "status": {
+      "type": "string",
+      "description": "Overall execution status"
+    },
+    "command": {
+      "type": "string",
+      "description": "Command that generated this output"
+    }
+  },
+  "$defs": {
+    "action_result": {
+      "type": "object",
+      "required": ["target", "action", "outcome"],
+      "properties": {
+        "target": {
+          "type": "object",
+          "required": ["pid"],
+          "properties": {
+            "pid": { "type": "integer" },
+            "start_id": { "type": "string" }
+          }
+        },
+        "action": { "type": "string" },
+        "outcome": {
+          "type": "string",
+          "enum": ["success", "skipped", "failed", "blocked"]
+        },
+        "reason": { "type": "string" },
+        "duration_ms": { "type": "integer", "minimum": 0 },
+        "error": { "type": "string" }
+      }
+    }
+  }
+}

